        } | ForEach-Object {
            $hwnd = $_.MainWindowHandle.ToInt64()
            $results += [PSCustomObject]@{
                pid = $_.Id
                name = $_.ProcessName
                window_title = $_.MainWindowTitle
                hwnd = $hwnd
                has_window = ($hwnd -ne 0)
                path = $_.Path
            }
        }
        $results | ConvertTo-Json -Compress -AsArray
        '''
        result = self._run_powershell(script)
        try:
            # 提取JSON部分
            start = result.find('[')
