            # 可能是单个对象
            start = result.find('{')
            end = result.rfind('}') + 1
            if start >= 0 and end > start:
                data = json.loads(result[start:end])
                return [data] if isinstance(data, dict) else data
        except Exception as e:
            print(f"Parse error: {e}, raw result: {result[:500]}", file=sys.stderr)
        return []

