    """小豆芽控制器 - 封装Windows UI Automation操作"""

    def __init__(self):
        self.powershell_path = "/mnt/c/Windows/System32/windowspowershell/v1.0/powershell.exe"

    def _run_powershell(self, script: str) -> str:
        """执行PowerShell脚本并返回结果"""
        try:
            result = subprocess.run(
                [self.powershell_path, "-Command", script],
                capture_output=True,
                text=True,
                timeout=30
            )
            return result.stdout + result.stderr
        except subprocess.TimeoutExpired:
            return "Error: PowerShell command timed out"
        except Exception as e:
            return f"Error executing PowerShell: {str(e)}"

    def discover(self) -> List[Dict[str, Any]]:
        """发现所有小豆芽进程"""
        script = '''
        $results = @()
        Get-Process | Where-Object { 
            $_.Path -like "*xiaodouya*" -or 
            $_.ProcessName -match "douya|С��ѿ|豆芽" 
        } | ForEach-Object {
            $results += [PSCustomObject]@{
                pid = $_.Id
                name = $_.ProcessName
                window_title = $_.MainWindowTitle
                hwnd = $_.MainWindowHandle.ToInt64()
                path = $_.Path
            }
        }
        $results | ConvertTo-Json -Compress
        '''
        result = self._run_powershell(script)
        try:
            # 解析JSON结果
            if result.strip():
                data = json.loads(result.strip())
                if isinstance(data, dict):
                    return [data]
                return data
        except json.JSONDecodeError:
            pass
        return []

