function Write-Log {
    param(
        [string]$Message,
        [ValidateSet("INFO", "SUCCESS", "WARNING", "ERROR")]
        [string]$Level = "INFO"
    )

    $timestamp = Get-Date -Format "HH:mm:ss"
    $color = switch ($Level) {
        "INFO" { "White" }
        "SUCCESS" { "Green" }
        "WARNING" { "Yellow" }
        "ERROR" { "Red" }
    }

    Write-Host "[$timestamp] [$Level] $Message" -ForegroundColor $color
}

function Wait-ForSeconds {
    param([int]$Seconds = 2)
    Write-Log "等待 $Seconds 秒..." -Level "INFO"
    Start-Sleep -Seconds $Seconds
}

function Wait-ForMilliseconds {
    param([int]$Milliseconds = 500)
    Start-Sleep -Milliseconds $Milliseconds
}

